#include "fan_pwm.h"
#include <Arduino.h>
#define FAN_PWM 25
#define FAN_TACH 34
static uint8_t _speed=0;static volatile uint16_t _pulses=0;static uint16_t _rpm=0;static unsigned long _last=0;
void IRAM_ATTR _fan_isr(){_pulses++;}
void fan_setup(){ledcAttach(FAN_PWM,25000,8);pinMode(FAN_TACH,INPUT_PULLUP);attachInterrupt(FAN_TACH,_fan_isr,FALLING);Serial.println("[fan] OK");}
void fan_set_speed(uint8_t p){_speed=constrain(p,0,100);ledcWrite(FAN_PWM,map(_speed,0,100,0,255));}
uint8_t fan_get_speed(){return _speed;}
uint16_t fan_get_rpm(){if(millis()-_last>=1000){_rpm=_pulses*30;_pulses=0;_last=millis();}return _rpm;}
